const exportInternReportCSV=name=>{const d=internMap[name];if(!d)return;const rows=[];Object.entries(d.milestones).forEach(([ms,dt])=>{if(dt.intern)rows.push({Name:name,Milestone:ms,Type:"Self",...Object.fromEntries(Object.entries(dt.intern).filter(([k])=>!["Name","Email","Milestone","Timestamp","_type"].includes(k)))});if(dt.manager)rows.push({Name:name,Milestone:ms,Type:"Manager",...Object.fromEntries(Object.entries(dt.manager).filter(([k])=>!["Intern Name","Manager Name","Manager Email","Milestone","Timestamp","_type"].includes(k)))});});if(rows.length)exportCSV(rows,`report_${name.replace(/\s+/g,"_")}.csv`);showToast("CSV exported");};
const exportInternReportXLSX=async name=>{const d=internMap[name];if(!d||!Object.keys(d.milestones).length){showToast("No data","danger");return;}if(!window.XLSX){const s=document.createElement("script");s.src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";document.head.appendChild(s);await new Promise((r,j)=>{s.onload=r;s.onerror=j;});}const X=window.XLSX,wb=X.utils.book_new();const cM=[{k:["Tasks"],l:"Tasks"},{k:["Product"],l:"Product understanding"},{k:["Workflow"],l:"Processes & Workflow"},{k:["Communication"],l:"Communication"}];const fv=(resp,ka)=>{if(!resp)return"—";for(const k of ka){if(resp[k]!==undefined&&resp[k]!=="")return String(resp[k]);const f=Object.keys(resp).find(rk=>rk.toLowerCase().includes(k.toLowerCase()));if(f&&resp[f]!=="")return String(resp[f]);}return"—";};["1 month","3 months","6 months"].filter(ms=>d.milestones[ms]).forEach(ms=>{const mD=d.milestones[ms],iR=mD.intern||null,mR=mD.manager||null,rows=[];rows.push([`Internship Feedback Report — ${name}`,"",""]);rows.push(["","",""]);rows.push([`📅 ${ms} Milestone`,"",""]);rows.push(["Category","Manager","Intern"]);[...cM,{k:["Growth","Support","Feedback Seeking"],l:ms==="6 months"?"Feedback Seeking / Support":"Growth & Learning"}].forEach(f=>{rows.push([f.l,mR?fv(mR,f.k):"—",iR?fv(iR,f.k):"—"]);});if(ms==="6 months"){rows.push([""]);rows.push(["Milestone Questions","",""]);rows.push(["Category","Manager","Intern"]);rows.push(["Impact delivered so far",mR?fv(mR,["Impact"]):"—",iR?fv(iR,["Impact"]):"—"]);}rows.push([""]);rows.push(["Manager-only assessment","",""]);[{k:["Overall"],l:"Overall Performance"},{k:["Readiness"],l:"Readiness"}].forEach(f=>{const v=mR?fv(mR,f.k):"—";if(v!=="—")rows.push([f.l,v,"—"]);});rows.push([""]);rows.push(["Intern-only assessment","",""]);[{k:["Expectations","Role"],l:"Role Clarity"},{k:["Support"],l:"Support"},{k:["Enjoyment"],l:"Enjoyment"},{k:["Priorities"],l:"Priorities"}].forEach(f=>{const v=iR?fv(iR,f.k):"—";if(v!=="—")rows.push([f.l,"—",v]);});rows.push([""]);rows.push(["💬 Qualitative Feedback","",""]);rows.push(["Manager","",""]);Object.entries(mR||{}).filter(([k,v])=>typeof v==="string"&&v.length>20&&!["Timestamp","Manager Name","Manager Email","Intern Name","Milestone"].includes(k)).forEach(([k,v])=>{rows.push([k+":",v,""]);});rows.push(["Intern","",""]);Object.entries(iR||{}).filter(([k,v])=>typeof v==="string"&&v.length>20&&!["Timestamp","Name","Email","Milestone"].includes(k)).forEach(([k,v])=>{rows.push([k+":",v,""]);});const ws=X.utils.aoa_to_sheet(rows);ws["!cols"]=[{wch:42},{wch:60},{wch:30}];ws["!merges"]=[{s:{r:0,c:0},e:{r:0,c:2}}];X.utils.book_append_sheet(wb,ws,ms==="1 month"?"1 month report":ms==="3 months"?"3 month report":"6 month report");});X.writeFile(wb,`${name.replace(/\s+/g,"_")}_feedback.xlsx`);showToast("XLSX downloaded");};
const[form,setForm]=useState({Name:"",Team:"",StartDate:"","Team leader":"",Result:"In progress",Comments:""});
const openAddIntern=()=>{setForm({Name:"",Team:"",StartDate:"","Team leader":"",Result:"In progress",Comments:""});setEditIntern(null);setModalOpen(true);};
const openEditIntern=r=>{setForm({Name:r.Name||"",Team:r.Team||"",StartDate:r["Start date.1"]||r["Start date"]||"","Team leader":r["Team leader"]||"",Result:r.Result||"In progress",Comments:r.Comments||""});setEditIntern(r);setModalOpen(true);};
